const body = items[0].json;
let canal, user_id, texto, nombre;
if (body.message && body.message.from) {
  // Telegram
  canal = 'telegram';
  user_id = String(body.message.from.id);
  texto = body.message.text || '';
  nombre = body.message.from.first_name || '';
} else if (body.author) {
  // Discord
  canal = 'discord';
  user_id = String(body.author.id);
  texto = body.content || '';
  nombre = body.author.username || '';
} else if (body.entry) {
  // WhatsApp Cloud API
  const change = body.entry[0].changes[0].value;
  const msg = (change.messages || [])[0] || {};
  canal = 'whatsapp';
  user_id = msg.from || '';
  texto = msg.text ? msg.text.body : '';
  nombre = (change.contacts && change.contacts[0] && change.contacts[0].profile.name) || '';
} else {
  canal = 'desconocido'; user_id = ''; texto = ''; nombre = '';
}
return [{ json: { canal, user_id, texto, nombre } }];

const materias = new Set();
for (const item of items) {
  const lista = (item.json.especialidad_materias || '').split(',').map(m => m.trim()).filter(Boolean);
  lista.forEach(m => materias.add(m));
}
const arr = [...materias];
const mensaje = arr.map((m, i) => `${i + 1}. ${m}`).join('\n');
return [{ json: { listaMaterias: arr.map((m,i)=>({indice:i+1, materia:m})), mensaje } }];

const sesion = JSON.parse($input.first().json.datos_parciales || '[]');
const opcion = parseInt($('Normalizar Mensaje').item.json.texto);
const match = sesion.find(m => m.indice === opcion);
return [{ json: { valido: !!match, materiaElegida: match ? match.materia : null } }];

const texto = $('Normalizar Mensaje').item.json.texto;
const regex = /^\d{4}-\d{2}-\d{2}$/;
const formatoOk = regex.test(texto);
const fecha = formatoOk ? new Date(texto + 'T00:00:00') : null;
const hoy = new Date(); hoy.setHours(0,0,0,0);
const esFutura = formatoOk && fecha > hoy;
const dias = ['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'];
return [{ json: { valida: formatoOk && esFutura, fecha: texto, diaSemana: formatoOk ? dias[fecha.getDay()] : null } }];

const tutores = $('Leer Tutores Por Materia').all().map(i => i.json);
const dispoRaw = $('Leer Disponibilidad').all().map(i => i.json);
const vistos = new Set();
const dispo = dispoRaw.filter(d => { if (vistos.has(d.id_dispo)) return false; vistos.add(d.id_dispo); return true; });
const sesion = $('Buscar Sesión Activa').first().json;
const datosParciales = JSON.parse(sesion.datos_parciales || '{}');
const materia = datosParciales.materia;
const cruce = dispo.filter(d => tutores.some(t => t.id_tutor === d.id_tutor && (t.especialidad_materias||'').includes(materia))).map(d => { const t = tutores.find(t => t.id_tutor === d.id_tutor); return { id_tutor: d.id_tutor, nombre: t.nombre, id_dispo: d.id_dispo, hora_inicio: d.hora_inicio, hora_fin: d.hora_fin, chat_id: t.chat_id || '', canal: t.canal || 'telegram' }; });
return cruce.length ? cruce.map(c => ({ json: c, pairedItem: { item: 0 } })) : [{ json: { sinDisponibilidad: true }, pairedItem: { item: 0 } }];

const texto = ($('Normalizar Mensaje').item.json.texto || '').trim().toLowerCase();
const sesion = $('Buscar Sesión Activa').first().json;
const datosParciales = JSON.parse(sesion.datos_parciales || '{}');
const candidatos = datosParciales.candidatos || [];

if (['no', 'n', 'cancelar'].includes(texto)) {
    return [{ json: { respuesta: 'cancelar' } }];
}

const numero = parseInt(texto, 10);
if (!isNaN(numero) && numero >= 1 && numero <= candidatos.length) {
    const seleccion = candidatos[numero - 1];
    return [{ json: { respuesta: 'seleccion', seleccion } }];
}

return [{ json: { respuesta: 'invalido' } }];

const cand = $('Interpretar Respuesta').item.json.seleccion || {};
const datos = JSON.parse($('Buscar Sesión Activa').first().json.datos_parciales || '{}');
const mensaje = `📚 ¡Tienes una nueva tutoría asignada!\nMateria: ${datos.materia}\nFecha: ${datos.fecha}\nHorario: ${cand.hora_inicio} - ${cand.hora_fin}`;
return [{ json: { canal: cand.canal || 'telegram', destinatario: cand.chat_id || '', mensaje } }];

const candidatos = $input.all().map(i => i.json);
const estudiante = $('Normalizar Mensaje').item.json;

const lineas = candidatos.map((c, idx) => `${idx + 1}. ${c.nombre} (${c.hora_inicio}-${c.hora_fin})`);
const texto = `Estos son los tutores disponibles:\n${lineas.join('\n')}\n\nResponde con el número de la opción que prefieras (o escribe 'cancelar' para cancelar).`;

return [{ json: { canal: estudiante.canal, destinatario: estudiante.user_id, mensaje: texto, candidatos } }];
